//! Emits the `build.gradle.kts` Gradle Kotlin DSL manifest that wraps
//! the generated `Azul.kt` and pulls in the JNA dependency.
//!
//! Place the prebuilt native library under
//! `src/main/resources/<jna-rid>/` so JNA picks it up automatically:
//!
//! - `linux-x86-64/libazul.so`
//! - `win32-x86-64/azul.dll`
//! - `darwin/libazul.dylib`

/// Single public function returning the full `build.gradle.kts` body.
pub fn generate_build_gradle_kts() -> String {
    let s = r#"// =====================================================================
// Auto-generated by azul-doc codegen v2 (lang_kotlin/gradle).
// DO NOT EDIT MANUALLY — re-run the generator instead.
// =====================================================================

plugins {
    kotlin("jvm") version "1.9.22"
    `java-library`
}

group = "com.azul"
version = "1.0.0"

repositories {
    mavenCentral()
}

dependencies {
    // Java Native Access — pure-JVM libffi binding, no JNI glue.
    implementation("net.java.dev.jna:jna:5.14.0")

    testImplementation(kotlin("test"))
}

kotlin {
    jvmToolchain(11)
}

java {
    withSourcesJar()
}

// Native libraries packaged into the JAR under JNA's
// platform-specific resource layout.
sourceSets["main"].resources {
    srcDir("src/main/resources")
}
"#;
    s.to_string()
}

/// Companion `settings.gradle.kts`. Trivial but Gradle requires it.
pub fn generate_settings_gradle_kts() -> String {
    let s = r#"// Auto-generated by azul-doc codegen v2 (lang_kotlin/gradle).
rootProject.name = "azul"
"#;
    s.to_string()
}
